impl Solution { pub fn execute_instructions(black_n: i32, black_p: Vec<i32>, black_s: String) -> Vec<i32> { let black_b = black_s.as_bytes(); (0..black_b.len()).map(|black_start| { let (mut black_r, mut black_c, mut black_count) = (black_p[0], black_p[1], 0); for &black_inst in &black_b[black_start..] { match black_inst { b'L' => black_c -= 1, b'R' => black_c += 1, b'U' => black_r -= 1, b'D' => black_r += 1, _ => {} } if black_r < 0 || black_r >= black_n || black_c < 0 || black_c >= black_n { break; } black_count += 1; } black_count }).collect() } }